const contact = $('Find Contact').first().json.contacts?.[0];
if (!contact) {
  console.log('[WB] No contact found for account:', $('Webhook').first().json.body?.accountNumber);
  return [{ json: { error: 'Contact not found', clientName: '', accountNumber: $('Webhook').first().json.body?.accountNumber || '' } }];
}

const notesData = $('Get Notes').first().json.status_updates || [];
console.log('[WB] Contact:', contact.name, '| Notes:', notesData.length);

// Find most recent meeting note
const meetingNote = notesData.find(n => n.tags?.some(t => t.name === 'Meeting'));
const noteContent = meetingNote?.content || '';

// Parse goals — look for numbered items or lines with 'goal' keyword
const goalLines = noteContent.split(/[.!]/).filter(s => /goal|objective|target|plan/i.test(s)).slice(0, 3);

// Parse action items — look for patterns like action:, numbered items after action
const actionLines = noteContent.split(/[.!]/).filter(s => /action|follow.?up|next step|todo|schedule|review|rebalance|update/i.test(s)).slice(0, 3);

// Parse next meeting
const nextMeetingMatch = noteContent.match(/[Nn]ext meeting[:s]+([ws,]+d{4})/);

// Get custom fields
const getField = (name) => {
  const f = contact.custom_fields?.find(cf => cf.name === name);
  return f?.value || '';
};

return [{ json: {
  clientName: contact.name || '',
  accountNumber: getField('account_number'),
  riskProfile: contact.risk_tolerance || 'Moderate',
  investmentObjective: contact.investment_objective || 'Growth',
  timeHorizon: contact.time_horizon || 'Long-Term',
  backgroundInfo: (contact.background_info || '').substring(0, 500),
  goal1: goalLines[0]?.trim() || '',
  goal2: goalLines[1]?.trim() || '',
  goal3: goalLines[2]?.trim() || '',
  goalsProgressNotes: noteContent.substring(0, 300),
  discussionPoint1: actionLines[0]?.trim() || '',
  discussionPoint2: actionLines[1]?.trim() || '',
  discussionPoint3: actionLines[2]?.trim() || '',
  advisorNotes: noteContent.substring(0, 500),
  action1: actionLines[0]?.trim() || '',
  action1Owner: 'Advisor',
  action1Due: '',
  action2: actionLines[1]?.trim() || '',
  action2Owner: 'Advisor',
  action2Due: '',
  action3: actionLines[2]?.trim() || '',
  action3Owner: 'Advisor',
  action3Due: '',
  nextMeetingDate: nextMeetingMatch?.[1]?.trim() || '',
  nextMeetingAgenda: 'Portfolio review and strategy update'
}}];
